patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 6fe969358185..c12e58fc6e20 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -853,6 +853,7 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();
@@ -1004,9 +1005,20 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
     }
   }

+  // add (umax X, C1), -C1 --> usub.sat X, C1
+  const APInt *C1;
+  if (match(Op0, m_OneUse(m_Intrinsic<Intrinsic::umax>(m_Value(X),
+                                                       m_APInt(C1)))) &&
+      *C1 == -*C) {
+    Function *USubSat = Intrinsic::getDeclaration(
+        Add.getModule(), Intrinsic::usub_sat, Ty);
+    return CallInst::Create(USubSat, {X, ConstantInt::get(Ty, *C1)});
+  }
+
   return nullptr;
 }

+
 // match variations of a^2 + 2*a*b + b^2
 //
 // to reuse the code between the FP and Int versions, the instruction OpCodes
